import { Injectable, inject, signal, computed } from '@angular/core';
import { CustomService, MPageService } from '@clinicaloffice/mpage-developer';
import { OncSchedConfiguration } from '../models/schedule.model';

const DMINFO_DOMAIN = 'ONC_SCHED';
const DMINFO_NAME = 'APP_CONFIG';

@Injectable({ providedIn: 'root' })
export class ConfigurationService {
  private readonly customService = inject(CustomService);
  private readonly mPage = inject(MPageService);

  private readonly _configuration = signal<OncSchedConfiguration | null>(null);
  private readonly _loading = signal(false);

  readonly configuration = this._configuration.asReadonly();
  readonly isLoaded = computed(() => this._configuration() !== null);
  readonly loading = this._loading.asReadonly();

  loadConfiguration(): void {
    this._loading.set(true);
    const dmInfo = this.customService.emptyDmInfo;
    dmInfo.infoDomain = DMINFO_DOMAIN;
    dmInfo.infoName = DMINFO_NAME;
    dmInfo.infoDomainId = 0;

    // Timeout fallback: if DMInfo callback never fires, set empty config
    const fallbackTimeout = setTimeout(() => {
      if (this._configuration() === null) {
        this.mPage.putLog('Config load timeout - using defaults');
        this._configuration.set({ UPDT_DT_TM: '', APPOINTMENT_TYPES: [] });
        this._loading.set(false);
      }
    }, 5000);

    this.customService.executeDmInfoAction('loadAppConfig', 'r', [dmInfo], () => {
      clearTimeout(fallbackTimeout);
      try {
        const result = this.customService.get('loadAppConfig');
        const longText = result?.dmInfo?.[0]?.longText
          ?? result?.longText
          ?? result?.infoLongText;
        if (longText) {
          const config = JSON.parse(longText) as OncSchedConfiguration;
          this._configuration.set(config);
        } else {
          this._configuration.set({
            UPDT_DT_TM: '',
            APPOINTMENT_TYPES: []
          });
        }
      } catch {
        this.mPage.putLog('Failed to parse app configuration');
        this._configuration.set({
          UPDT_DT_TM: '',
          APPOINTMENT_TYPES: []
        });
      }
      this._loading.set(false);
    });
  }

  saveConfiguration(config: OncSchedConfiguration): void {
    this._loading.set(true);
    config.UPDT_DT_TM = new Date().toISOString();

    const dmInfo = this.customService.emptyDmInfo;
    dmInfo.infoDomain = DMINFO_DOMAIN;
    dmInfo.infoName = DMINFO_NAME;
    dmInfo.infoDomainId = 0;
    dmInfo.infoLongText = JSON.stringify(config);

    this.customService.executeDmInfoAction('saveAppConfig', 'w', [dmInfo], () => {
      this._configuration.set({ ...config });
      this._loading.set(false);
      this.mPage.putLog('App configuration saved');
    });
  }

  clearCache(): void {
    this._configuration.set(null);
  }
}
